#include<bits/stdc++.h>
using namespace std;
const long long nulltag=1e12;
long long a[300010],sum[300010],blksiz,blk[300010],blkl[300010],blkr[300010],tag[300010];
void pushdown(long long x)
{
    if(tag[x]==nulltag)
    {
        return;
    }
    for(long long i=blkl[x];i<=blkr[x];i++)
    {
        a[i]=tag[x];
    }
    tag[x]=nulltag;
}
long long query_update(long long l,long long r,long long val)
{
    long long ans=0;
    if(blk[l]==blk[r])
    {
        pushdown(blk[l]);
        for(long long i=l;i<=r;i++)
        {
            if(a[i]==val)
            {
                ans++;
            }
            a[i]=val;
        }
        return ans;
    }
    pushdown(blk[l]);
    for(long long i=l;i<=blkr[blk[l]];i++)
    {
        if(a[i]==val)
        {
            ans++;
        }
        a[i]=val;
    }
    pushdown(blk[r]);
    for(long long i=blkl[blk[r]];i<=r;i++)
    {
        if(a[i]==val)
        {
            ans++;
        }
        a[i]=val;
    }
    for(long long i=blk[l]+1;i<blk[r];i++)
    {
        if(tag[i]==nulltag)
        {
            for(long long j=blkl[i];j<=blkr[i];j++)
            {
                if(a[j]==val)
                {
                    ans++;
                }
            }
            tag[i]=val;
        }
        else
        {
            if(tag[i]==val)
            {
                ans+=blkr[i]-blkl[i]+1;
            }
            tag[i]=val;
        }
    }
    return ans;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    blksiz=sqrt(n);
    for(long long i=1;blksiz*(i-1)+1<=n;i++)
    {
        tag[i]=nulltag;
        blkl[i]=blksiz*(i-1)+1;
        blkr[i]=min(n,blksiz*i);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        blk[i]=(i+blksiz-1)/blksiz;
    }
    while(n--)
    {
        long long l,r,c;
        scanf("%lld%lld%lld",&l,&r,&c);
        printf("%lld\n",query_update(l,r,c));
    }
    return 0;
}
